components.css:
nav {
  background: var(--a-surface-raised);
  border-bottom: 1px solid var(--a-border);
  padding: var(--a-space-md) 0;
}

nav ul {
  list-style: none;
  display: flex;
  gap: var(--a-space-lg);
  padding: 0 var(--a-space-md);
  margin: 0;
}

nav a {
  color: var(--a-text-main);
  text-decoration: none;
  padding: var(--a-space-sm) var(--a-space-md);
  transition: all var(--a-transition-base);
}

nav a:hover {
  color: var(--a-primary);
  border-bottom: 2px solid var(--a-primary);
}

nav {
  background: var(--a-surface-overlay);
  padding: var(--a-space-md);
  border-radius: var(--a-radius-md);
}

nav ul {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: var(--a-space-sm);
  padding: 0;
  margin: 0;
}

nav a {
  display: block;
  padding: var(--a-space-sm) var(--a-space-md);
  color: var(--a-text-main);
  text-decoration: none;
  border-radius: var(--a-radius-sm);
  transition: all var(--a-transition-base);
  border-left: 3px solid transparent;
}

nav a:hover {
  background: var(--a-surface-base);
  color: var(--a-primary);
  border-left-color: var(--a-primary);
  padding-left: calc(var(--a-space-md) + 3px);
}

nav ol {
  list-style: none;
  display: flex;
  gap: var(--a-space-sm);
  padding: 0;
  margin: var(--a-space-md) 0;
}

nav li::after {
  content: ' / ';
  color: var(--a-text-muted);
  margin-left: var(--a-space-sm);
}

nav li:last-child::after {
  content: '';
}

nav a {
  color: var(--a-primary);
  text-decoration: none;
}

nav [aria-current="page"] {
  color: var(--a-text-main);
  font-weight: var(--a-font-weight-medium);
}

button[role="tab"] {
  padding: var(--a-space-md) var(--a-space-lg);
  background: var(--a-surface-overlay);
  border: 1px solid var(--a-border);
  border-bottom: none;
  cursor: pointer;
  transition: all var(--a-transition-base);
}

button[role="tab"][aria-selected="true"] {
  background: var(--a-surface-base);
  border-bottom: 3px solid var(--a-primary);
}

section[role="tabpanel"] {
  padding: var(--a-space-lg);
  border: 1px solid var(--a-border);
  border-top: none;
}

nav ul {
  list-style: none;
  display: flex;
  gap: var(--a-space-xs);
  padding: 0;
  margin: var(--a-space-lg) 0;
}

nav a, nav button {
  padding: var(--a-space-sm) var(--a-space-md);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-md);
  text-decoration: none;
  cursor: pointer;
  transition: all var(--a-transition-base);
}

nav a:hover, nav button:hover {
  border-color: var(--a-primary);
  color: var(--a-primary);
}

nav a[aria-current="page"] {
  background: var(--a-primary);
  color: var(--a-on-primary);
  border-color: var(--a-primary);
}

button#menu-toggle {
  background: transparent;
  border: none;
  font-size: var(--a-text-lg);
  cursor: pointer;
  padding: var(--a-space-sm);
}

aside#mobile-menu {
  position: fixed;
  top: 60px;
  right: 0;
  width: 300px;
  height: calc(100vh - 60px);
  background: var(--a-surface-raised);
  border-left: 1px solid var(--a-border);
  transform: translateX(100%);
  transition: transform var(--a-transition-base);
}

aside#mobile-menu:not(.hidden) {
  transform: translateX(0);
}

footer nav {
  display: grid;
  gap: var(--a-space-2xl);
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  padding: var(--a-space-lg);
}

footer h3 {
  margin: 0 0 var(--a-space-md) 0;
}

footer ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

footer li {
  margin: 0 0 var(--a-space-sm) 0;
}
